  if (speedBadge) ctx.on(speedBadge, "click", () => cycleSpeed("up"));

  // Keyboard-shortcut events
  ctx.on(window, "audio:toggle-playback", togglePlayback);
  ctx.on(window, "audio:toggle-mute", () => {
    audio.muted = !audio.muted;
  });
