3	export interface ReaderSettings {
4		readonly fontFamily: "serif" | "sans" | "mono";
5		readonly fontSize: number;
6		readonly lineHeight: number;
7		readonly maxWidth: number;
8		readonly autoScroll: boolean;
9		readonly autoNextChapter: boolean;
10	}
11	
12	const DEFAULTS: ReaderSettings = Object.freeze({
13		fontFamily: "serif",
14		fontSize: 18,
15		lineHeight: 1.8,
16		maxWidth: 700,
17		autoScroll: true,
18		autoNextChapter: false,
19	});
20	
21	const FONT_FAMILIES = ["serif", "sans", "mono"] as const;
22	
23	function coerce(raw: unknown): Partial<ReaderSettings> {
24		if (!raw || typeof raw !== "object") return {};
25		const r = raw as Record<string, unknown>;
26		const out: { -readonly [K in keyof ReaderSettings]?: ReaderSettings[K] } = {};
27		if (typeof r.fontFamily === "string" && (FONT_FAMILIES as ReadonlyArray<string>).includes(r.fontFamily)) {
28			out.fontFamily = r.fontFamily as ReaderSettings["fontFamily"];
29		}
30		if (typeof r.fontSize === "number") out.fontSize = r.fontSize;
31		if (typeof r.lineHeight === "number") out.lineHeight = r.lineHeight;
32		if (typeof r.maxWidth === "number") out.maxWidth = r.maxWidth;
33		if (typeof r.autoScroll === "boolean") out.autoScroll = r.autoScroll;
34		if (typeof r.autoNextChapter === "boolean") out.autoNextChapter = r.autoNextChapter;
35		return out;
36	}
37	
38	const store = new PersistedRecord<ReaderSettings>(
39		"readaloud-reader-settings",
40		DEFAULTS,
41		coerce,
42	);
43	
44	type SettingsListener = (s: Readonly<ReaderSettings>) => void;
45	const listeners = new Set<SettingsListener>();
46	
47	export const readerSettings = {
48		get(): Readonly<ReaderSettings> {
49			return store.get();
50		},
51		set(patch: Partial<ReaderSettings>): Readonly<ReaderSettings> {
52			const next = store.set(patch);
53			for (const fn of listeners) fn(next);
54			return next;
55		},
56		subscribe(fn: SettingsListener): () => void {
57			listeners.add(fn);
58			return () => listeners.delete(fn);
59		},
60		defaults: DEFAULTS,
61	};

