67	function findActiveWord(timings: ReadonlyArray<WordTiming>, ms: number): number {
68		let idx = -1;
69		let lo = 0;
70		let hi = timings.length - 1;
71		while (lo <= hi) {
72			const mid = (lo + hi) >>> 1;
73			const t = timings[mid];
74			if (!t) break;
75			if (ms >= t.startMs && ms < t.endMs) {
76				idx = mid;
77				break;
78			} else if (ms < t.startMs) {
79				hi = mid - 1;
80			} else {
81				idx = mid;
82				lo = mid + 1;
83			}
84		}
85		if (idx >= 0 && idx < timings.length - 1) {
86			const next = timings[idx + 1];
87			if (next && ms >= next.startMs) idx += 1;
88		}
89		return idx;
90	}
