9	class ScrollFollowController {
10		private state: ScrollFollowState = Object.freeze({
11			playing: false,
12			autoScrollPaused: false,
13			inAutoScroll: false,
14		});
15		private readonly listeners = new Set<Listener>();
16		private autoScrollEndTimer: number | undefined;
17	
18		get(): ScrollFollowState {
19			return this.state;
20		}
21	
22		subscribe(fn: Listener): () => void {
23			this.listeners.add(fn);
24			return () => this.listeners.delete(fn);
25		}
26	
27		setPlaying(playing: boolean): void {
28			this.update({ playing });
29		}
30	
31		beginAutoScroll(graceMs = 800): void {
32			this.update({ inAutoScroll: true });
33			if (this.autoScrollEndTimer !== undefined) clearTimeout(this.autoScrollEndTimer);
34			this.autoScrollEndTimer = window.setTimeout(() => {
35				this.update({ inAutoScroll: false });
36				this.autoScrollEndTimer = undefined;
37			}, graceMs);
38		}
39	
40		manualScroll(): void {
41			if (!this.state.playing || this.state.inAutoScroll) return;
42			if (this.state.autoScrollPaused) return;
43			this.update({ autoScrollPaused: true });
44		}
45	
46		resume(): void {
47			if (!this.state.autoScrollPaused) return;
48			this.update({ autoScrollPaused: false });
49		}
50	
51		private update(patch: Partial<ScrollFollowState>): void {
52			const next = Object.freeze({ ...this.state, ...patch });
53			if (
54				next.playing === this.state.playing &&
55				next.autoScrollPaused === this.state.autoScrollPaused &&
56				next.inAutoScroll === this.state.inAutoScroll
