1	export interface ScrubberOptions<T> {
2		readonly el: HTMLElement;
3		readonly indexAt: (clientX: number) => T;
4		readonly preview: (value: T, clientX: number) => void;
5		readonly commit: (value: T) => void;
6		readonly previewEnd?: () => void;
7	}
8	
9	export function attachScrubber<T>(opts: ScrubberOptions<T>): () => void {
10		const { el, indexAt, preview, commit, previewEnd } = opts;
11		let isDragging = false;
12	
13		const previewAt = (clientX: number): T => {
14			const v = indexAt(clientX);
15			preview(v, clientX);
16			return v;
17		};
18	
19		const onMouseDown = (e: MouseEvent): void => {
20			isDragging = true;
21			previewAt(e.clientX);
22			e.preventDefault();
23		};
24		const onMouseMove = (e: MouseEvent): void => {
25			if (isDragging) previewAt(e.clientX);
26		};
27		const onMouseUp = (e: MouseEvent): void => {
28			if (!isDragging) return;
29			isDragging = false;
30			previewEnd?.();
31			commit(indexAt(e.clientX));
32		};
33		const onClick = (e: MouseEvent): void => {
34			if (!isDragging) commit(indexAt(e.clientX));
35		};
36	
37		const onTouchStart = (e: TouchEvent): void => {
38			isDragging = true;
39			const t = e.touches[0];
40			if (t) previewAt(t.clientX);
41			e.preventDefault();
42		};
43		const onTouchMove = (e: TouchEvent): void => {
44			if (!isDragging) return;
45			const t = e.touches[0];
46			if (t) previewAt(t.clientX);
47			e.preventDefault();
48		};
49		const onTouchEnd = (e: TouchEvent): void => {
50			if (!isDragging) return;
51			isDragging = false;
52			previewEnd?.();
53			e.preventDefault();
54			const t = e.changedTouches[0];
55			if (t) commit(indexAt(t.clientX));
56		};
57	
58		el.addEventListener("mousedown", onMouseDown);
59		el.addEventListener("click", onClick);
60		window.addEventListener("mousemove", onMouseMove);
61		window.addEventListener("mouseup", onMouseUp);
62		el.addEventListener("touchstart", onTouchStart, { passive: false });
63		el.addEventListener("touchmove", onTouchMove, { passive: false });
64		el.addEventListener("touchend", onTouchEnd, { passive: false });
65	
66		return () => {
67			el.removeEventListener("mousedown", onMouseDown);
68			el.removeEventListener("click", onClick);
69			window.removeEventListener("mousemove", onMouseMove);
70			window.removeEventListener("mouseup", onMouseUp);
71			el.removeEventListener("touchstart", onTouchStart);
72			el.removeEventListener("touchmove", onTouchMove);
73			el.removeEventListener("touchend", onTouchEnd);
74		};
75	}
