77	export function fractionAt(el: HTMLElement, clientX: number): number {
78		const rect = el.getBoundingClientRect();
79		if (rect.width === 0) return 0;
80		return Math.min(1, Math.max(0, (clientX - rect.left) / rect.width));
81	}

