1	export class PersistedRecord<T extends object> {
2		private current: Readonly<T>;
3	
4		constructor(
5			private readonly key: string,
6			private readonly defaults: Readonly<T>,
7			private readonly coerce?: (raw: unknown) => Partial<T>,
8		) {
9			this.current = this.read();
10		}
11	
12		private read(): Readonly<T> {
13			const raw = localStorage.getItem(this.key);
14			if (!raw) return this.defaults;
15			try {
16				const parsed = JSON.parse(raw) as unknown;
17				const patch = this.coerce ? this.coerce(parsed) : (parsed as Partial<T>);
18				return Object.freeze({ ...this.defaults, ...patch });
19			} catch {
20				return this.defaults;
21			}
22		}
23	
24		get(): Readonly<T> {
25			return this.current;
26		}
27	
28		set(patch: Partial<T>): Readonly<T> {
29			this.current = Object.freeze({ ...this.current, ...patch });
30			localStorage.setItem(this.key, JSON.stringify(this.current));
31			return this.current;
32		}
33	}

1	export function cycleOption<T extends number | string>(
2		values: ReadonlyArray<T>,
3		current: T,
4		direction: "up" | "down",
5		eq: (a: T, b: T) => boolean = (a, b) => a === b,
6	): T {
7		if (values.length === 0) return current;
8		const idx = values.findIndex((v) => eq(v, current));
9		const safeIdx = idx < 0 ? 0 : idx;
10		const nextIdx =
11			direction === "up"
12				? Math.min(values.length - 1, safeIdx + 1)
13				: Math.max(0, safeIdx - 1);
14		return values[nextIdx] ?? current;
15	}

