65		TDataset = Record<string, string | undefined>,
66	>(setup: (ctx: HookContext<TEl, TDataset>) => void): LiveViewHookSpec {
67		return {
68			mounted(this: ViewHookInternal): void {
69				const disposers: Array<() => void> = [];
70				const lv = this;
71	
72				const ctx: HookContext<TEl, TDataset> = {
73					el: this.el as TEl,
74					dataset: this.el.dataset as unknown as Readonly<TDataset>,
75	
76					on(
77						target: EventTarget,
78						event: string,
79						handler: (arg: unknown) => void,
80						opts?: AddEventListenerOptions,
81					): void {
82						if (target === window && isReadaloudEvent(event)) {
83							const wrapped = (e: Event): void => {
84								const detail = (e as CustomEvent).detail;
85								handler(detail);
86							};
87							window.addEventListener(event, wrapped);
88							disposers.push(() => window.removeEventListener(event, wrapped));
89						} else {
90							target.addEventListener(event, handler as EventListener, opts);
91							disposers.push(() => target.removeEventListener(event, handler as EventListener, opts));
92						}
93					},
94	
95					dispatch(event: string, detail?: unknown): void {
96						window.dispatchEvent(new CustomEvent(event, { detail }));
97					},
98	
99					pushEvent(event: string, payload?: object): void {
100						lv.pushEvent(event, payload ?? {});
101					},
102	
103					handleEvent(event: string, handler: (payload: never) => void): void {
104						const ref = lv.handleEvent(event, handler as (p: unknown) => void);
105						disposers.push(() => lv.removeHandleEvent(ref));
106					},
107	
108					onDestroy(fn: () => void): void {
109						disposers.push(fn);
110					},
111				};
112	
113				(this as unknown as { _ctxDisposers: Array<() => void> })._ctxDisposers = disposers;
114	
115				try {
116					setup(ctx);
117				} catch (err) {
118					for (const dispose of disposers) {
119						try {
120							dispose();
121						} catch {}
122					}
123					throw err;
124				}
125			},
126	
127			destroyed(this: ViewHookInternal): void {
128				const disposers = (this as unknown as { _ctxDisposers?: Array<() => void> })._ctxDisposers;
129				if (!disposers) return;
130				for (const dispose of disposers) {
131					try {
132						dispose();
133					} catch (err) {
134						console.error("hook disposer threw:", err);
135					}
136				}
137			},
138		};
139	}

